    const localVar = 'I am inside the function';
    console.log(localVar);
}
myFunction();
// console.log(localVar); // Error: localVar is not defined
// Output:
// I am inside the function

// Block scope example
if (true) {
    let blockVar = 'I am inside the block';
    console.log(blockVar);
}
// console.log(blockVar); // Error: blockVar is not defined
// Output:
// I am inside the block

// var, let, const with scope example
if (true) {
    var varVariable = 'With var';
    let letVariable = 'With let';
    const constVariable = 'With const';
    console.log(varVariable);
    console.log(letVariable);
    console.log(constVariable);
}
console.log(varVariable);
// console.log(letVariable); // Error: letVariable is not defined
// console.log(constVariable); // Error: constVariable is not defined
// Output:
// With var
// With let
// With const
// With var

// Hoisting and scope example
console.log(varHoist); // undefined
var varHoist = 'Var hoisting';
// console.log(letHoist); // Error: Cannot access 'letHoist' before initialization
let letHoist = 'Let hoisting';
function testHoist() {
    console.log(localHoist); // undefined
    var localHoist = 'Inside function';
}
